1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return no living cells for an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill cells that have only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive that has exactly 2 live neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
20	  });
21	  it("should keep a live cell alive that has exactly 3 live neighbors (survival)", () => {
22	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
23	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
24	  });
25	  it("should kill a live cell that has more than 3 live neighbors (overpopulation)", () => {
26	    const result = nextGeneration([
27	      [0, 0], [1, 0], [2, 0],
28	      [0, 1], [1, 1], [2, 1],
29	      [0, 2], [1, 2], [2, 2],
30	    ]);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should bring a dead cell to life that has exactly 3 live neighbors (reproduction)", () => {
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    expect(result).toContainEqual([1, 1]);
36	  });
37	  it("should not bring a dead cell to life that has fewer than 3 live neighbors", () => {
38	    const result = nextGeneration([[0, 0], [1, 0]]);
39	    expect(result).toEqual([]);
40	  });
41	  it("should keep a block pattern unchanged across a generation (still life)", () => {
42	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
43	    const result = nextGeneration(block);
44	    expect(result).toHaveLength(4);
45	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
46	  });
47	  it.todo("should oscillate a blinker pattern to its alternate form");
48	});
